            {columns.map((col, i) => (
              <th
                key={col}
                className={`px-4 py-3 text-left font-medium text-gray-700 whitespace-nowrap ${
                  i === 0 ? 'sticky left-0 z-10 bg-gray-50' : ''
                }`}
              >
                {col}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {data.map((row, rowIdx) => (
            <tr key={rowIdx} className="border-b last:border-0 hover:bg-gray-50">
              {columns.map((col, i) => (
                <td
                  key={col}
