        <Popover.Trigger className="inline-flex items-center justify-center w-5 h-5 rounded-full bg-gray-200 text-xs">ⓘ</Popover.Trigger>
        <Popover.Portal>
          <Popover.Content className="bg-gray-900 text-white text-sm px-3 py-2 rounded-md max-w-xs" sideOffset={5}>
            {content}
            <Popover.Arrow className="fill-gray-900" />
          </Popover.Content>
        </Popover.Portal>
      </Popover.Root>
    );
  }

  return (
    <Tooltip.Root>
      <Tooltip.Trigger className="inline-flex items-center justify-center w-5 h-5 rounded-full bg-gray-200 text-xs">ⓘ</Tooltip.Trigger>
      <Tooltip.Portal>
