    </Tooltip.Root>
  );
}
```

Tooltips are for supplementary info. If the content is essential, use a Popover or inline text instead. Tooltips should never contain interactive content like links or buttons.

If you're building a modal without Radix UI, you must implement a focus trap to meet accessibility requirements. Focus should cycle within the modal while it's open.

```tsx
import { useEffect, useRef, useCallback } from 'react';

export function useFocusTrap(isOpen: boolean) {
  const containerRef = useRef<HTMLDivElement>(null);

  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    if (e.key !== 'Tab' || !containerRef.current) return;

    const focusableElements = containerRef.current.querySelectorAll<HTMLElement>(
      'a[href], button:not([disabled]), textarea, input, select, [tabindex]:not([tabindex="-1"])'
    );
    const firstEl = focusableElements[0];
    const lastEl = focusableElements[focusableElements.length - 1];

    if (e.shiftKey) {
      if (document.activeElement === firstEl) {
        e.preventDefault();
        lastEl.focus();
      }
    } else {
      if (document.activeElement === lastEl) {
        e.preventDefault();
        firstEl.focus();
      }
    }
  }, []);

  useEffect(() => {
    if (!isOpen) return;
    const previouslyFocused = document.activeElement as HTMLElement;
    document.addEventListener('keydown', handleKeyDown);

    // Focus first focusable element
    const firstFocusable = containerRef.current?.querySelector<HTMLElement>(
      'a[href], button:not([disabled]), textarea, input, select'
    );
    firstFocusable?.focus();

    return () => {
      document.removeEventListener('keydown', handleKeyDown);
      previouslyFocused?.focus(); // Restore focus on close
    };
  }, [isOpen, handleKeyDown]);

  return containerRef;
}
```

Usage:
```tsx
function Modal({ isOpen, onClose, children }) {
  const trapRef = useFocusTrap(isOpen);
  if (!isOpen) return null;
  return <div ref={trapRef} role="dialog" aria-modal="true">{children}</div>;
}
```

This handles: Tab cycling, Shift+Tab reverse cycling, auto-focus on open, and focus restoration on close.
